// |       |  +      + - +---+ - +
// |       | /       |   |   |   |
// +-------+         + - + - + - +
// Desired padding on the destination rect
int paddingInPixelsOneDirection = 16;
// Multiply by two for the total padding along an axis.
int paddingInPixels = 2 * paddingInPixelsOneDirection;
Vector4 center3by3 = new Vector4(1.0f/3.0f, 1.0f/3.0f, 1.0f/3.0f, 1.0f/3.0f);
Vector2 subTextureSize = new Vector2(sourceWidth, sourceHeight);
// HDR to non-HDR decoding is not necessary here so drop the
// last parameter.
Blitter.BlitCubeToOctahedral2DQuadWithPadding(cmd, source, subTextureSize, center3by3, 2, paddingInPixels);

// Copy the third mip level of a source cube map texture to the center rect
// of a 3x3 grid on the current render target, like so:
//    +-------+      + - + - + - +
//  /       / |      |   |   |   |
// +-------+  |      + - +---+ - +
// |       |  |  --> |   | X |   |
// |       |  +      + - +---+ - +
// |       | /       |   |   |   |
// +-------+         + - + - + - +
Vector4 center3by3 = new Vector4(1.0f/3.0f, 1.0f/3.0f, 1.0f/3.0f, 1.0f/3.0f);
Blitter.BlitCubeToOctahedral2DQuadSingleChannel(cmd, source, center3by3, 2);

// Copy the top right quadrant of the source texture's first mip level to the bottom left
// quadrant of the current render target, without bilinear filtering.
Vector4 topRight = new Vector4(0.5f, 0.5f, 0.5f, 0.5f);
Vector4 bottomLeft = new Vector4(0.5f, 0.5f, 0.0f, 0.0f);
Blitter.BlitQuadSingleChannel(cmd, source, topRight, bottomLeft, 0, false);

enum BufferType
{
    Color,
    Depth
}

void Render()
{
    var camera = GetCamera();
    var buffers = GetFrameHistoryBuffersFor(camera);

    // Set reference size in case the rendering size changed this frame
    buffers.SetReferenceSize(
        GetCameraWidth(camera), GetCameraHeight(camera),
        GetCameraUseMSAA(camera), GetCameraMSAASamples(camera)
    );
    buffers.Swap();

    var currentColor = buffer.GetFrameRT((int)BufferType.Color, 0);
    if (currentColor == null) // Buffer was not allocated
    {
        buffer.AllocBuffer(
            (int)BufferType.Color,      // Color buffer id
            ColorBufferAllocator,       // Custom functor to implement allocation
            2                           // Use 2 RT for this buffer for double buffering
        );
        currentColor = buffer.GetFrameRT((int)BufferType.Color, 0);
    }

    var previousColor = buffers.GetFrameRT((int)BufferType.Color, 1);

    // Use previousColor and write into currentColor
}

{
    AnimationCurve curve0 = new AnimationCurve();
    curve0.AddKey(new Keyframe(0.0f, 3.0f));
    curve0.AddKey(new Keyframe(4.0f, 2.0f));

    AnimationCurve curve1 = new AnimationCurve();
    curve1.AddKey(new Keyframe(0.0f, 0.0f));
    curve1.AddKey(new Keyframe(2.0f, 1.0f));
    curve1.AddKey(new Keyframe(4.0f, 4.0f));

    float t = 0.5f;
    KeyframeUtility.InterpAnimationCurve(curve0, curve1, t);

    // curve0 now stores the resulting interpolated curve
}

using UnityEngine;
